    public String toString() {
        return "PricingSessionWindow("
                + "marketId="
                + marketId
                + ", timezone="
                + timezone
                + ", sessionOpen="
                + sessionOpen
                + ", sessionClose="
                + sessionClose
                + ")";
    }

